class Solution:
    def repairCars(self, ranks: List[int], cars: int) -> int:
        def possible(time):
            cnt = 0
            for r in ranks:
                cnt += (time // (r * r))
            return cnt >= cars
        l, r = 1, 10**14
        while l < r:
            mid = (l + r) // 2
            if possible(mid):
                r = mid
            else:
                l = mid + 1
        return l
